const performers = $input.item.json;
const top = Array.isArray(performers) ? performers[0] : performers;

const name = top?.name ?? 'Top AI Engineer';
const skill = top?.top_skill ?? 'AI automation';
const score = top?.trust_score ?? 95;
const deployments = top?.deployment_count ?? 12;
const earnings = top?.earnings_usd ? `$${top.earnings_usd.toLocaleString()}` : '$8,400';

const script = `[HOOK — 0–3s]
This ${skill} engineer just earned ${earnings} this week on AiStaff.
Here's exactly how the platform works.

[PROBLEM — 3–10s]
Hiring AI talent the old way: NDAs unsigned, payments disputed, code shipped with no accountability.

[SOLUTION — 10–25s]
AiStaff uses Groth16 zero-knowledge proofs to verify every engineer's identity — no raw biometric data stored anywhere.
Every deployment gets a 30-second human veto window before any money moves.
Escrow is held until your Definition of Done checklist passes.

[SOCIAL PROOF — 25–45s]
${name} has a trust score of ${score}/100 — that's GitHub commits, LinkedIn verification, and a ZK biometric proof combined.
${deployments} successful deployments this month. 7-day warranty on every one.

[CTA — 45–60s]
Link in bio — aistaffglobal.com
Browse verified AI talent. Escrow-backed. Ship with confidence.`;

return [{ json: { script, performer_name: name, performer_skill: skill, trust_score: score, week: new Date().toISOString().slice(0, 10) } }];
